<div class="page-head"><div><h2>Training</h2><p class="muted">Training program, budget tracking, workflow status, and report.</p></div></div>
<div class="grid grid-2"><div class="card"><h3>Create Program</h3><form method="post" action="<?=url('/training/store')?>"><?=csrf_field()?><div class="form-row"><div><label>Program Name</label><input name="name" required></div><div><label>Budget</label><input name="budget" type="number" step="0.01"></div><div><label>Start Date</label><input name="start_date" type="date"></div><div><label>End Date</label><input name="end_date" type="date"></div><div><label>Status</label><select name="status"><option>planned</option><option>approved</option><option>running</option><option>completed</option><option>cancelled</option></select></div></div><br><button class="btn btn-primary">Save Program</button></form></div><div class="card"><h3>Report</h3><div class="grid grid-3"><div><div class="muted">Programs</div><div class="stat"><?=count($rows)?></div></div><div><div class="muted">Budget</div><div class="stat"><?=money_id(array_sum(array_map(fn($r)=>(float)$r['budget'],$rows)))?></div></div><div><div class="muted">Completed</div><div class="stat"><?=count(array_filter($rows,fn($r)=>$r['status']==='completed'))?></div></div></div></div></div><br>
<div class="card"><h3>List Data & Workflow</h3><table class="table"><tr><th>Name</th><th>Date</th><th>Budget</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['name'])?></td><td><?=e($r['start_date'])?> - <?=e($r['end_date'])?></td><td><?=money_id($r['budget'])?></td><td><span class="badge badge-info"><?=e($r['status'])?></span></td><td><form method="post" action="<?=url('/training/workflow')?>" style="display:flex;gap:6px"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($r['id'])?>"><select name="status"><option>planned</option><option>approved</option><option>running</option><option>completed</option><option>cancelled</option></select><button class="btn btn-light">Update</button></form></td></tr><?php endforeach; ?></table></div>
